class Solution:
    def maxDistance(self, position, m):
        """
        :type position: List[int]
        :type m: int
        :rtype: int
        """
        position.sort()

        def canPlace(min_dist):
            # Check if we can place m balls with minimum distance min_dist
            count = 1
            last_pos = position[0]
            for i in range(1, len(position)):
                if position[i] - last_pos >= min_dist:
                    count += 1
                    last_pos = position[i]
                    if count == m:
                        return True
            return False

        left, right = 1, position[-1] - position[0]
        result = 1

        while left <= right:
            mid = (left + right) // 2
            if canPlace(mid):
                result = mid
                left = mid + 1
            else:
                right = mid - 1

        return result
